프로젝트 구조와 스킬 파일을 충분히 파악했습니다. 이제 프로필 수정 API 인터페이스를 설계하겠습니다.

---

# Maum 앱 프로필 수정 API 인터페이스 설계

## 1. 현재 스키마 분석 결과

프로젝트에 기존 프로필 관련 코드가 없으므로, 다음 컨벤션을 기반으로 신규 설계합니다.

- **GraphQL 스키마 위치**: `graphql/src/main/resources/graphql/schema.graphqls`
- **Proto 위치**: `protobuf/src/main/proto/profile/profile.proto`
- **Controller 위치**: `graphql/src/main/kotlin/com/maum/backend/controller/profile/`
- **Service 위치**: `graphql/src/main/kotlin/com/maum/backend/service/profile/`
- **DB Catalog**: `maum` (entity-skill 기준 - user, profile 도메인)

---

## 2. GraphQL 뮤테이션 스키마

**파일 경로**: `/graphql/src/main/resources/graphql/profile.graphqls`

```graphql
# ──────────────────────────────────────────
# Types
# ──────────────────────────────────────────

type Profile {
    userId: ID!
    nickname: String!
    bio: String
    profileImageUrl: String
    birthDate: String             # "YYYY-MM-DD" 형식
    gender: Gender
    interests: [Interest!]!
    location: Location
    voiceIntroUrl: String         # 음성 소개 (Maum 앱 특화)
    mannerScore: Float            # 매너 점수 (읽기 전용)
    updatedAt: String!
}

type Location {
    regionName: String!           # "서울특별시 강남구"
    latitude: Float
    longitude: Float
}

type Interest {
    code: String!
    label: String!
}

enum Gender {
    MALE
    FEMALE
    OTHER
    PREFER_NOT_TO_SAY
}

# ──────────────────────────────────────────
# Input Types  (명명 규칙: {Action}{Domain}Input)
# ──────────────────────────────────────────

input UpdateProfileInput {
    nickname: String              # null이면 변경 없음 (Partial Update)
    bio: String                   # null이면 변경 없음; 빈 문자열("")이면 삭제
    profileImageUrl: String       # null이면 변경 없음; 빈 문자열("")이면 삭제
    birthDate: String             # "YYYY-MM-DD"; 최초 1회만 변경 허용
    gender: Gender                # 최초 1회만 변경 허용
    interestCodes: [String!]      # null이면 변경 없음; 빈 배열이면 전체 삭제
    location: UpdateLocationInput
    voiceIntroUrl: String         # null이면 변경 없음; 빈 문자열("")이면 삭제
}

input UpdateLocationInput {
    regionName: String!
    latitude: Float
    longitude: Float
}

# ──────────────────────────────────────────
# Query / Mutation
# ──────────────────────────────────────────

extend type Query {
    myProfile: Profile!
    userProfile(userId: ID!): Profile
}

extend type Mutation {
    updateProfile(input: UpdateProfileInput!): Profile!
    deleteProfileImage: Boolean!
    deleteVoiceIntro: Boolean!
}
```

### 설계 포인트

| 항목 | 결정 | 이유 |
|---|---|---|
| Partial Update | 모든 필드 Optional | 클라이언트가 변경된 필드만 전송 가능 |
| birthDate / gender | String / Enum, 최초 1회 변경 | 데이팅 앱 특성상 위변조 방지 |
| interestCodes | `[String!]` (코드값) | 관심사 마스터 데이터는 별도 Query로 조회 |
| voiceIntroUrl | URL만 저장 | 실제 파일 업로드는 S3 Pre-signed URL 별도 처리 |
| mannerScore | Profile 타입에만 존재, Input에 없음 | 시스템 산정값, 사용자 직접 수정 불가 |

---

## 3. gRPC Proto 정의

**파일 경로**: `/protobuf/src/main/proto/profile/profile.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// ──────────────────────────────────────────
// Service
// ──────────────────────────────────────────

service ProfileService {
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc DeleteProfileImage(DeleteProfileImageRequest) returns (DeleteProfileImageResponse);
  rpc DeleteVoiceIntro(DeleteVoiceIntroRequest) returns (DeleteVoiceIntroResponse);
  rpc ListInterests(ListInterestsRequest) returns (ListInterestsResponse);
}

// ──────────────────────────────────────────
// Messages - Profile
// ──────────────────────────────────────────

message Profile {
  string user_id = 1;
  string nickname = 2;
  optional string bio = 3;
  optional string profile_image_url = 4;
  optional string birth_date = 5;        // "YYYY-MM-DD"
  optional string gender = 6;            // MALE | FEMALE | OTHER | PREFER_NOT_TO_SAY
  repeated Interest interests = 7;
  optional Location location = 8;
  optional string voice_intro_url = 9;
  optional double manner_score = 10;
  string updated_at = 11;
}

message Location {
  string region_name = 1;
  optional double latitude = 2;
  optional double longitude = 3;
}

message Interest {
  string code = 1;
  string label = 2;
}

// ──────────────────────────────────────────
// Messages - GetProfile
// ──────────────────────────────────────────

message GetProfileRequest {
  string requester_user_id = 1;    // 조회 요청자 (권한 체크용)
  string target_user_id = 2;       // 조회 대상
}

message GetProfileResponse {
  Profile profile = 1;
}

// ──────────────────────────────────────────
// Messages - UpdateProfile
// ──────────────────────────────────────────

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string bio = 3;                // 빈 문자열 = 삭제
  optional string profile_image_url = 4;  // 빈 문자열 = 삭제
  optional string birth_date = 5;
  optional string gender = 6;
  repeated string interest_codes = 7;     // 빈 배열 = 전체 삭제
  bool update_interests = 8;              // interest_codes 변경 여부 명시 플래그
  optional LocationInput location = 9;
  optional string voice_intro_url = 10;   // 빈 문자열 = 삭제
}

message LocationInput {
  string region_name = 1;
  optional double latitude = 2;
  optional double longitude = 3;
}

message UpdateProfileResponse {
  Profile profile = 1;
}

// ──────────────────────────────────────────
// Messages - DeleteProfileImage
// ──────────────────────────────────────────

message DeleteProfileImageRequest {
  string user_id = 1;
}

message DeleteProfileImageResponse {
  bool success = 1;
}

// ──────────────────────────────────────────
// Messages - DeleteVoiceIntro
// ──────────────────────────────────────────

message DeleteVoiceIntroRequest {
  string user_id = 1;
}

message DeleteVoiceIntroResponse {
  bool success = 1;
}

// ──────────────────────────────────────────
// Messages - ListInterests (마스터 데이터)
// ──────────────────────────────────────────

message ListInterestsRequest {}

message ListInterestsResponse {
  repeated Interest interests = 1;
}
```

### gRPC 설계 포인트

- `update_interests` 불리언 플래그를 별도로 두는 이유: proto3에서 `repeated` 필드는 비어 있을 때 "변경 없음"과 "전체 삭제" 구분이 불가능하기 때문입니다.
- `optional` 키워드로 모든 선택 필드를 명시해 `hasField` 체크로 Partial Update를 안전하게 구현합니다.

