## 4. GraphQL Controller / Service 코드 예시

**파일 경로**: `/graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.getProfile(userId, userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun userProfile(
        @UserId userId: String,
        @Argument userId: String,
    ): ProfileResponse? {
        val response = profileService.getProfile(userId, userId)
        return response.profile?.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): ProfileResponse {
        val response = profileService.updateProfile(userId, input)
        return response.profile.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteProfileImage(
        @UserId userId: String,
    ): Boolean {
        return profileService.deleteProfileImage(userId).success
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteVoiceIntro(
        @UserId userId: String,
    ): Boolean {
        return profileService.deleteVoiceIntro(userId).success
    }
}
```

**파일 경로**: `/graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileService.kt`

```kotlin
@Service
class ProfileService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getProfile(requesterId: String, targetUserId: String): GetProfileResponse {
        val request = GetProfileRequest.newBuilder()
            .setRequesterUserId(requesterId)
            .setTargetUserId(targetUserId)
            .build()
        return try {
            stub.getProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val builder = UpdateProfileRequest.newBuilder().setUserId(userId)

        input.nickname?.let { builder.setNickname(it) }
        input.bio?.let { builder.setBio(it) }
        input.profileImageUrl?.let { builder.setProfileImageUrl(it) }
        input.birthDate?.let { builder.setBirthDate(it) }
        input.gender?.let { builder.setGender(it.name) }
        input.voiceIntroUrl?.let { builder.setVoiceIntroUrl(it) }
        input.location?.let {
            builder.setLocation(
                LocationInput.newBuilder()
                    .setRegionName(it.regionName)
                    .apply { it.latitude?.let { lat -> setLatitude(lat) } }
                    .apply { it.longitude?.let { lon -> setLongitude(lon) } }
                    .build()
            )
        }
        if (input.interestCodes != null) {
            builder.addAllInterestCodes(input.interestCodes)
            builder.setUpdateInterests(true)
        }

        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun deleteProfileImage(userId: String): DeleteProfileImageResponse {
        val request = DeleteProfileImageRequest.newBuilder().setUserId(userId).build()
        return try {
            stub.deleteProfileImage(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun deleteVoiceIntro(userId: String): DeleteVoiceIntroResponse {
        val request = DeleteVoiceIntroRequest.newBuilder().setUserId(userId).build()
        return try {
            stub.deleteVoiceIntro(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

